import Foundation
import Combine

struct DataFetcher {
    static func fetchData(from url: URL) -> AnyPublisher<Data, Error> {
        URLSession.shared.dataTask(with: url)
            .publisher
            .map { (data, response) -> Data in
                data
            }
            .eraseToAnyPublisher()
    }
}

let url = URL(string: "https://www.example.com")!

DataFetcher.fetchData(from: url)
    .sink(receiveCompletion: {
        completion in
        switch completion {
        case .finished: print("Completed")
        case .failure(let error): print("Error: \(error)")
        }
    }, receiveValue: {
        data in
        if let string = String(data: data, encoding: .utf8) {
            print("Data: \(string)")
        }
    })
    .store(in: &Cancellables.shared)

class Cancellables {
    static var shared = Set<AnyCancellable>()
}
```
Giải thích: `DataFetcher` chứa hàm `fetchData` sử dụng `URLSession` để tải dữ liệu. `publisher` chuyển đổi `URLSession` task thành một Combine publisher. `map` trích xuất dữ liệu. `sink` là subscriber, xử lý dữ liệu hoặc lỗi. `eraseToAnyPublisher` ẩn chi tiết implementation.

