import CoreData

class CoreDataMigration {
    static func performMigration(persistentStoreCoordinator: NSPersistentStoreCoordinator) throws {
        // Lấy URL của store hiện tại
        guard let storeURL = persistentStoreCoordinator.persistentStoreURL(for: NSPersistentStoreSpec(url: NSPersistentStoreSpec.defaultConfigurationURL())) else { return }

        // Tạo một persistent store coordinator mới cho version 2
        let migrationCoordinator = NSPersistentStoreCoordinator(managedObjectModel: NSManagedObjectModel(contentsOf: Bundle.main.url(forResource: "YourModelVersion2", withExtension: "momd")!))

