        try migrationCoordinator.migratePersistentStore(from: storeURL, to: persistentStoreCoordinator.persistentStoreURL(for: NSPersistentStoreSpec(url: NSPersistentStoreSpec.defaultConfigurationURL()))!, options: nil, mappingModel: NSMappingModel(contentsOf: Bundle.main.url(forResource: "YourMappingModel", withExtension: "xcdatamodel")!))
    }
}

// Trong AppDelegate.swift, gọi hàm migration khi ứng dụng khởi động
func applicationDidFinishLaunching(_ application: UIApplication) -> Bool {
    // ...
    do {
        try CoreDataMigration.performMigration(persistentStoreCoordinator: persistentStoreCoordinator!)
    } catch {
        print("Migration failed: \(error)")
    }
    // ...
}
