import UIKit
import UserNotifications

class AppDelegate: UIResponder, UIApplicationDelegate, UNUserNotificationCenterDelegate {

    func application(_ application: UIApplication, didFinishLaunchingWithOptions launchOptions: [UIApplication.LaunchOptionsKey: Any]?) -> Bool {
        // Yêu cầu quyền thông báo
        UNUserNotificationCenter.current().requestAuthorization(options: [.alert, .sound, .badge]) {
            (granted, error) in
            if granted {
                print("Permission granted")
            } else {
                print("Permission denied")
            }
        }

        UNUserNotificationCenter.current().delegate = self
        return true
    }

    func application(_ application: UIApplication, didRegisterForRemoteNotificationsWithDeviceToken deviceToken: Data) {
        // Gửi device token lên server
        let tokenParts = deviceToken.map { data -> String in
            return String(format: "%02hhx", data)
        }
        let token = tokenParts.joined()
        print("Device Token: \(token)")
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, didReceive response: UNNotificationResponse, withCompletionHandler completionHandler: () -> Void) {
        // Xử lý khi người dùng tương tác với notification
        print("Notification received: \(response.notification.request.identifier)")
        completionHandler()
    }

    func userNotificationCenter(_ center: UNUserNotificationCenter, willPresent notification: UNNotification, withCompletionHandler completionHandler: (@escaping (UNNotificationPresentationOptions) -> Void)) {
        // Xử lý khi notification đến khi ứng dụng đang chạy
        completionHandler([.alert, .sound, .badge])
    }
}
```
