import SwiftUI

struct AsyncImageView: View {
    let url: URL
    @State private var image: Image? = nil
    @State private var isLoading: Bool = true
    @State private var errorMessage: String? = nil

    var body: some View {
        VStack {
            if let image = image {
                image
                    .resizable()
                    .scaledToFit()
                    .frame(width: 200, height: 200)
            } else if isLoading {
                ProgressView()
            } else if let errorMessage = errorMessage {
                Text("Error: \(errorMessage)")
            }
        }
        .task {
            do {
                let (data, _) = try await URLSession.shared.data(from: url)
                if let uiImage = UIImage(data: data) {
                    image = Image(uiImage: uiImage)
                }
                isLoading = false
            } catch {
                errorMessage = error.localizedDescription
                isLoading = false
            }
        }
    }
}
```
Giải thích: `AsyncImageView` sử dụng `@State` để quản lý `image`, `isLoading`, và `errorMessage`. `.task` tạo một asynchronous task để tải hình ảnh. `await` tạm dừng execution cho đến khi dữ liệu được tải. `try catch` xử lý các lỗi có thể xảy ra.

